final:
module RefModule( A, B, Ci, S, Co );input A, B, Ci;
  output S, Co;

  wire   n1, n2, n3;

  // Calculate sum (S)
  assign n1 = A ^ B;    // XOR
  assign S = n1 ^ Ci;   // XOR with carry-in

  // Calculate carry out (Co)
  wire temp1_A = A;
  wire temp2_B = B;
  assign n2 = temp1_A & temp2_B;    // AND
  assign n3 = n1 & Ci;  // AND with carry-in
  assign Co = n2 | n3;  // OR for final carry out

endmodule
